from dataclasses import dataclass


@dataclass
class AgentRole:
    """
    Separates the three components of a persona so they can be varied
    independently across different agent configurations.
    """
    domain: str       # what the agent knows about
    function: str     # what it does in this run
    scope: str        # depth and breadth of its work

    def to_persona_line(self) -> str:
        """
        One-sentence persona suitable for the opening of the system prompt.
        Kept short so constraints and environment sections read clearly after it.
        """
        return (
            f"You are a {self.domain} specialist. "
            f"Your job is to {self.function}. "
            f"{self.scope}"
        )


# Single-agent examples
CODER_ROLE = AgentRole(
    domain="Python backend engineer working on a FastAPI service",
    function="fix the bug described in the task",
    scope="Keep changes minimal. Do not refactor unrelated code.",
)

REVIEWER_ROLE = AgentRole(
    domain="senior Python engineer",
    function="review the code change described in the task for correctness, security, and performance",
    scope="Output issues as a numbered list. End with VERDICT: APPROVE or VERDICT: REQUEST_CHANGES.",
)

TESTER_ROLE = AgentRole(
    domain="Python testing engineer",
    function="write pytest tests that cover the new behaviour described in the task",
    scope="Do not modify application code. Each test must have a one-line docstring.",
)

# In multi-agent systems, each agent has a distinct role.
# The function is what differentiates them — not the domain (they all share it).

SHARED_DOMAIN = "Python FastAPI e-commerce service (Python 3.12, SQLAlchemy, pytest)"

def make_system(role: AgentRole, constraints: list[str]) -> str:
    parts = [role.to_persona_line()]
    if constraints:
        constraint_lines = "\n".join(f"- {c}" for c in constraints)
        parts.append(f"Constraints:\n{constraint_lines}")
    return "\n\n".join(parts)


ORCHESTRATOR_SYSTEM = make_system(
    AgentRole(
        domain=SHARED_DOMAIN,
        function="break the task into subtasks and delegate each to the right specialist",
        scope="Do not do any coding, testing, or reviewing yourself.",
    ),
    constraints=[
        "Delegate to: 'coder', 'tester', or 'reviewer'.",
        "Synthesise the agents' results into a single final answer.",
    ],
)

CODER_SYSTEM = make_system(
    AgentRole(
        domain=SHARED_DOMAIN,
        function="implement the code change described in the task",
        scope="Return the complete modified file, not a diff.",
    ),
    constraints=[
        "Do not modify tests/.",
        "Run the test suite after making changes and stop if tests fail.",
    ],
)

TESTER_SYSTEM = make_system(
    AgentRole(
        domain=SHARED_DOMAIN,
        function="write or update tests to cover the code change described in the task",
        scope="Do not modify application code.",
    ),
    constraints=[
        "Use pytest. Each test must have a one-line docstring.",
    ],
)

import anthropic

client = anthropic.Anthropic()


def run_with_role(role: AgentRole, task: str, tools: list[dict]) -> str:
    """
    Agent loop with a structured role. The role is serialised into the
    system prompt; the task goes in messages[0].
    """
    system = role.to_persona_line()

    messages = [{"role": "user", "content": task}]

    for step in range(30):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": dispatch_tool(block.name, block.input),
                })
        messages.append({"role": "user", "content": tool_results})

    return "Max steps reached."


def dispatch_tool(name: str, input: dict) -> str:
    return f"result of {name}"

import pytest


class TestAgentRole:
    def test_to_persona_line_contains_all_components(self):
        role = AgentRole(
            domain="Python engineer",
            function="fix bugs",
            scope="Keep changes minimal.",
        )
        line = role.to_persona_line()
        assert "Python engineer" in line
        assert "fix bugs" in line
        assert "Keep changes minimal" in line

    def test_to_persona_line_is_string(self):
        role = AgentRole(domain="X", function="Y", scope="Z")
        assert isinstance(role.to_persona_line(), str)

    def test_different_roles_produce_different_prompts(self):
        coder = AgentRole(domain="backend engineer", function="fix the bug", scope="minimal change")
        reviewer = AgentRole(domain="senior engineer", function="review the code", scope="list issues")
        assert coder.to_persona_line() != reviewer.to_persona_line()
